INSERT INTO _import_feat_data (name, category, prerequisite_text, is_repeatable, description) VALUES
    ('Actor', 'General', 'Level 4, Charisma 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Charisma score by 1, to a maximum of 20. Impersonation: While you''re disguised as a real or fictional person, you have Advantage on Charisma (Deception or Performance) checks to convince others that you are that person.'),
    ('Athlete', 'General', 'Level 4 + Strength 13+,Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Climb Speed: You gain a Climb Speed equal to your Speed.'),
    ('Blessed Warrior', 'Fighting Style', 'Paladin) (Special', False, 'You learn two Cleric cantrips of your choice. Guidance and Sacred Flame are recommended. The chosen cantrips count as Paladin spells for you, and Charisma is your spellcasting ability for them. Whenever you gain a Paladin level, you can replace one of these cantrips with another Cleric cantrip.'),
    ('Blind Fighting', 'Fighting Style', 'Fighting Style Feature', False, 'You have Blindsight with a range of 10 feet.'),
    ('Boon of Energy Resistance', 'Epic Boon', 'Level 19+', False, 'You gain the following benefits. Ability Score Increase: Increase one ability score of your choice by 1, to a maximum of 30. Energy Resistances: You gain Resistance to two of the following damage types of your choice: Acid, Cold, Fire, Lightning, Necrotic, Poison, Psychic, Radiant, or Thunder. Whenever you finish a Long Rest, you can change your choices.'),
    ('Boon of Fortitude', 'Epic Boon', 'Level 19+', False, 'You gain the following benefits. Ability Score Increase: Increase one ability score of your choice by 1, to a maximum of 30. Fortified Health: Your Hit Point maximum increases by 40. In addition, whenever you regain Hit Points, you can regain additional Hit Points equal to your Constitution modifier. Once you''ve regained these additional Hit Points, you can''t do so again until the start of your next turn.'),
    ('Boon of Recovery', 'Epic Boon', 'Level 19+', False, 'You gain the following benefits. Ability Score Increase: Increase one ability score of your choice by 1, to a maximum of 30. Last Stand: When you would be reduced to 0 Hit Points, you can drop to 1 Hit Point instead and regain a number of Hit Points equal to half your Hit Point maximum. Once you use this benefit, you can''t use it again until you finish a Long Rest.'),
    ('Boon of Skill', 'Epic Boon', 'Level 19+', False, 'You gain the following benefits. Ability Score Increase: Increase one ability score of your choice by 1, to a maximum of 30. All-Around Adept: You gain proficiency in all skills.'),
    ('Boon of Speed', 'Epic Boon', 'Level 19+', False, 'You gain the following benefits. Ability Score Increase: Increase one ability score of your choice by 1, to a maximum of 30. Escape Artist: As a Bonus Action, you can take the Disengage action, which also ends the Grappled condition on you.'),
    ('Charger', 'General', 'Level 4 + Strength 13+,Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Improved Dash: When you take the Dash action, your Speed increases by 10 feet for that action.'),
    ('Chef', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Constitution or Wisdom by 1, to a maximum of 20. Cook''s Utensils: You gain proficiency with Cook''s Utensils if you don''t already have it.'),
    ('Crafter', 'Origin', NULL, False, 'You gain the following benefits. Tool Proficiency: You gain proficiency with three different Artisan''s Tools of your choice from the Fast Crafting table. Discount: Whenever you buy a nonmagical item, you receive a 20 percent discount on it.'),
    ('Crossbow Expert', 'General', 'Level 4, Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Dexterity score by 1, to a maximum of 20. Ignore Loading: You ignore the Loading property of the Hand Crossbow, Heavy Crossbow, and Light Crossbow (all called crossbows elsewhere in this feat). If you''re holding one of them, you can load a piece of ammunition into it even if you lack a free hand.'),
    ('Crusher', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Constitution by 1, to a maximum of 20. Push: Once per turn, when you hit a creature with an attack that deals Bludgeoning damage, you can move it 5 feet to an unoccupied space if the target is no more than one size larger than you.'),
    ('Defensive Duelist', 'General', 'Level 4, Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Dexterity score by 1, to a maximum of 20. Parry: If you''re holding a Finesse weapon and another creature hits you with a melee attack, you can take a Reaction to add your Proficiency Bonus to your Armor Class, potentially causing the attack to miss you. You gain this bonus to your AC against melee attacks until the start of your next turn.'),
    ('Druidic Warrior', 'Fighting Style', 'Ranger) (Special', False, 'You learn two Druid cantrips of your choice. Guidance and Starry Wisp are recommended. The chosen cantrips count as Ranger spells for you, and Wisdom is your spellcasting ability for them. Whenever you gain a Ranger level, you can replace one of these cantrips with another Druid cantrip.'),
    ('Dual Wielder', 'General', 'Level 4 + Strength 13+,Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Enhanced Dual Wielding: When you take the Attack action on your turn and attack with a weapon that has the Light property, you can make one extra attack as a Bonus Action later on the same turn with a different weapon, which must be a Melee weapon that lacks the Two-Handed property. You don''t add your ability modifier to the extra attack''s damage unless that modifier is negat...'),
    ('Dueling', 'Fighting Style', 'Fighting Style Feature', False, 'When you''re holding a Melee weapon in one hand and no other weapons, you gain a +2 bonus to damage rolls with that weapon.'),
    ('Durable', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Constitution score by 1, to a maximum of 20. Defy Death: You have Advantage on Death Saving Throws.'),
    ('Elemental Adept', 'General', 'Level 4, Spellcasting', True, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Energy Mastery: Choose one of the following damage types: Acid, Cold, Fire, Lightning, or Thunder. Spells you cast ignore Resistance to damage of the chosen type. In addition, when you roll damage for a spell you cast that deals damage of that type, you can treat any 1 on a damage die as a 2.'),
    ('Fey-Touched', 'General', 'Level 4', False, 'Your exposure to the Feywild''s magic grants you the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Fey Magic: Choose one level 1 spell from the Divination or Enchantment school of magic. You always have that spell and the Misty Step spell prepared. You can cast each of these spells without expending a spell slot. Once you cast either spell in this way, you can''t cast that spell in this way again until you finish a Long Res...'),
    ('Great Weapon Master', 'General', 'Level 4, Strength 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength score by 1, to a maximum of 20. Heavy Weapon Mastery: When you hit a creature with a weapon that has the Heavy property as part of the Attack action on your turn, you can cause the weapon to deal extra damage to the target. The extra damage equals your Proficiency Bonus.'),
    ('Healer', 'Origin', NULL, False, 'You gain the following benefits. Battle Medic: If you have a Healer''s Kit, you can expend one use of it and tend to a creature within 5 feet of yourself as a Utilize action. That creature can expend one of its Hit Point Dice, and you then roll that die. The creature regains a number of Hit Points equal to the roll plus your Proficiency Bonus. Healing Rerolls: Whenever you roll a die to determine the number of Hit Points you restore with a spell or with this feat''s Battle Medic benefit, you ca...'),
    ('Heavily Armored', 'General', 'Level 4, M. Armor Trai.', False, 'You gain the following benefits. Ability Score Increase: Increase your Constitution or Strength by 1, to a maximum of 20. Armor Training: You gain training with Heavy armor.'),
    ('Heavy Armor Master', 'General', 'Level 4, H. Armor Trai.', False, 'You gain the following benefits. Ability Score Increase: Increase your Constitution or Strength by 1, to a maximum of 20. Damage Reduction: When you''re hit by an attack while you''re wearing Heavy armor, any Bludgeoning, Piercing, and Slashing damage dealt to you by that attack is reduced by an amount equal to your Proficiency Bonus.'),
    ('Inspiring Leader', 'General', 'Level 4 + Wisdom 13+,Charisma 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Wisdom or Charisma by 1, to a maximum of 20. Bolstering Performance: When you finish a Short or Long Rest, you can give an inspiring performance: a speech, song, or dance. When you do so, choose up to six allies (which can include yourself) within 30 feet of yourself who witness the performance. The chosen creatures each gain Temporary Hit Points equal to your character level plus the modifier of the ability you increased ...'),
    ('Interception', 'Fighting Style', 'Fighting Style Feature', False, 'When a creature you can see hits another creature within 5 feet of you with an attack roll, you can take a Reaction to reduce the damage dealt to the target by 1d10 plus your Proficiency Bonus. You must be holding a Shield or a Simple or Martial weapon to use this Reaction.'),
    ('Keen Mind', 'General', 'Level 4, Intelligence 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence score by 1, to a maximum of 20. Lore Knowledge: Choose one of the following skills: Arcana, History, Investigation, Nature, or Religion. If you lack proficiency in the chosen skill, you gain proficiency in it, and if you already have proficiency in it, you gain Expertise in it.'),
    ('Lightly Armored', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Armor Training: You gain training with Light armor and Shields.'),
    ('Lucky', 'Origin', NULL, False, 'You gain the following benefits. Luck Points: You have a number of Luck Points equal to your Proficiency Bonus and can spend the points on the benefits below. You regain your expended Luck Points when you finish a Long Rest. Advantage: When you roll a d20 for a D20 Test, you can spend 1 Luck Point to give yourself Advantage on the roll.'),
    ('Mage Slayer', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Concentration Breaker: When you damage a creature that is Concentrating, it has Disadvantage on the saving throw it makes to maintain Concentration.'),
    ('Martial Weapon Training', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Weapon Proficiency: You gain proficiency with Martial weapons.'),
    ('Medium Armor Master', 'General', 'Level 4, M. Armor Trai.', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Dexterous Wearer: While you''re wearing Medium armor, you can add 3, rather than 2 to your AC if you have a Dexterity score of 16 or higher.'),
    ('Moderately Armored', 'General', 'Level 4, L. Armor Trai.', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Armor Training: You gain training with Medium armor.'),
    ('Mounted Combatant', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength, Dexterity, or Wisdom by 1, to a maximum of 20. Mounted Strike: While mounted, you have Advantage on attack rolls against any unmounted creature within 5 feet of your mount that is at least one size smaller than the mount.'),
    ('Musician', 'Origin', NULL, False, 'You gain the following benefits. Instrument Training: You gain proficiency with three Musical Instruments of your choice. Encouraging Song: As you finish a Short or Long Rest, you can play a song on a Musical Instrument with which you have proficiency and give Heroic Inspiration to allies who hear the song. The number of allies you can affect in this way equals your Proficiency Bonus.'),
    ('Observant', 'General', 'Level 4 + Intelligence 13+,Wisdom 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence or Wisdom by 1, to a maximum of 20. Keen Observer: Choose one of the following skills: Insight, Investigation, or Perception. If you lack proficiency with the chosen skill, you gain proficiency in it, and if you already have proficiency in it, you gain Expertise in it.'),
    ('Piercer', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Puncture: Once per turn, when you hit a creature with an attack that deals Piercing damage, you can reroll one of the attack''s damage dice, and you must use the new roll.'),
    ('Poisoner', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Dexterity or Intelligence by 1, to a maximum of 20. Potent Poison: When you make a damage roll that deals Poison damage, it ignores Resistance to Poison damage.'),
    ('Polearm Master', 'General', 'Level 4 + Strength 13+,Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Dexterity or Strength by 1, to a maximum of 20. Pole Strike: Immediately after you take the Attack action and attack with a Quarterstaff, a Spear, or a weapon that has the Heavy and Reach properties, you can use a Bonus Action to make a melee attack with the opposite end of the weapon. The weapon deals Bludgeoning damage, and the weapon''s damage die for this attack is a d4.'),
    ('Protection', 'Fighting Style', 'Fighting Style Feature', False, 'When a creature you can see attacks a target other than you that is within 5 feet of you, you can take a Reaction to interpose your Shield if you''re holding one. You impose Disadvantage on the triggering attack roll and all other attack rolls against the target until the start of your next turn if you remain within 5 feet of the target.'),
    ('Resilient', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Choose one ability in which you lack saving throw proficiency. Increase the chosen ability score by 1, to a maximum of 20. Saving Throw Proficiency: You gain saving throw proficiency with the chosen ability.'),
    ('Ritual Caster', 'General', 'Level 4 + Intelligence 13+,Wisdom 13+,Charisma 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Ritual Spells: Choose a number of level 1 spells equal to your Proficiency Bonus that have the Ritual tag. You always have those spells prepared, and you can cast them with any spell slots you have. The spells'' spellcasting ability is the ability increased by this feat. Whenever your Proficiency Bonus increases thereafter, you can add an additional level 1 spell w...'),
    ('Sentinel', 'General', 'Level 4 + Strength 13+,Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Guardian: Immediately after a creature within 5 feet of you takes the Disengage action or hits a target other than you with an attack, you can make an Opportunity Attack against that creature.'),
    ('Shadow-Touched', 'General', 'Level 4', False, 'Your exposure to the Shadowfell''s magic grants you the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Shadow Magic: Choose one level 1 spell from the Illusion or Necromancy school of magic. You always have that spell and the Invisibility spell prepared. You can cast each of these spells without expending a spell slot. Once you cast either spell in this way, you can''t cast that spell in this way again until you finish a Lon...'),
    ('Sharpshooter', 'General', 'Level 4, Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Dexterity score by 1, to a maximum of 20. Bypass Cover: Your ranged attacks with weapons ignore Half Cover and Three-Quarters Cover.'),
    ('Shield Master', 'General', 'Level 4, Shield Trai.', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength score by 1, to a maximum of 20. Shield Bash: If you attack a creature within 5 feet of you as part of the Attack action and hit with a Melee weapon, you can immediately bash the target with your Shield if it''s equipped, forcing the target to make a Strength saving throw (DC 8 plus your Strength modifier and Proficiency Bonus). On a failed save, you either push the target 5 feet from you or cause it to have the Pro...'),
    ('Skill Expert', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase one ability score of your choice by 1, to a maximum of 20. Skill Proficiency: You gain proficiency in one skill of your choice.'),
    ('Skulker', 'General', 'Level 4, Dexterity 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Dexterity score by 1, to a maximum of 20. Blindsight: You have Blindsight with a range of 10 feet.'),
    ('Slasher', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Hamstring: Once per turn when you hit a creature with an attack that deals Slashing damage, you can reduce the Speed of that creature by 10 feet until the start of your next turn.'),
    ('Speedy', 'General', 'Level 4 + Dexterity 13+,Constitution 13+', False, 'You gain the following benefits. Ability Score Increase: Increase your Dexterity or Constitution by 1, to a maximum of 20. Speed Increase: Your Speed increases by 10 feet.'),
    ('Spell Sniper', 'General', 'Level 4, Spellcasting', False, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Bypass Cover: Your attack rolls for spells ignore Half Cover and Three-Quarters Cover.'),
    ('Tavern Brawler', 'Origin', NULL, False, 'You gain the following benefits. Enhanced Unarmed Strike: When you hit with your Unarmed Strike and deal damage, you can deal Bludgeoning damage equal to 1d4 plus your Strength modifier instead of the normal damage of an Unarmed Strike. Damage Rerolls: Whenever you roll a damage die for your Unarmed Strike, you can reroll the die if it rolls a 1, and you must use the new roll.'),
    ('Telekinetic', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Minor Telekinesis: You learn the Mage Hand spell. You can cast it without Verbal or Somatic components, you can make the spectral hand Invisible, and its range and the distance it can be away from you both increase by 30 feet when you cast it. The spell''s spellcasting ability is the ability increased by this feat.'),
    ('Telepathic', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Telepathic Utterance: You can speak telepathically to any creature you can see within 60 feet of yourself. Your telepathic utterances are in a language you know, and the creature understands you only if it knows that language. Your communication doesn''t give the creature the ability to respond to you telepathically.'),
    ('Thrown Weapon Fighting', 'Fighting Style', 'Fighting Style Feature', False, 'When you hit with a ranged attack roll using a weapon that has the Thrown property, you gain a +2 bonus to the damage roll.'),
    ('Tough', 'Origin', NULL, False, 'Your Hit Point maximum increases by an amount equal to twice your character level when you gain this feat. Whenever you gain a character level thereafter, your Hit Point maximum increases by an additional 2 Hit Points.'),
    ('Unarmed Fighting', 'Fighting Style', 'Fighting Style Feature', False, 'When you hit with your Unarmed Strike and deal damage, you can deal Bludgeoning damage equal to 1d6 plus your Strength modifier instead of the normal damage of an Unarmed Strike. If you aren''t holding any weapons or a Shield when you make the attack roll, the d6 becomes a d8. At the start of each of your turns, you can deal 1d4 Bludgeoning damage to one creature Grappled by you.'),
    ('War Caster', 'General', 'Level 4, Spellcasting', False, 'You gain the following benefits. Ability Score Increase: Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20. Concentration: You have Advantage on Constitution saving throws that you make to maintain Concentration.'),
    ('Weapon Master', 'General', 'Level 4', False, 'You gain the following benefits. Ability Score Increase: Increase your Strength or Dexterity by 1, to a maximum of 20. Mastery Property: Your training with weapons allows you to use the mastery property of one kind of Simple or Martial weapon of your choice, provided you have proficiency with it. Whenever you finish a Long Rest, you can change the kind of weapon to another eligible kind.');
INSERT INTO _import_feat_trait_data (feat_name, trait_name, description, sort_order) VALUES
    ('Actor', 'Actor: Ability Score Increase', 'Increase your Charisma score by 1, to a maximum of 20.', 10),
    ('Actor', 'Actor: Impersonation', 'While you''re disguised as a real or fictional person, you have Advantage on Charisma (Deception or Performance) checks to convince others that you are that person.', 20),
    ('Actor', 'Actor: Mimicry', 'You can mimic the sounds of other creatures, including speech. A creature that hears the mimicry must succeed on a Wisdom (Insight) check to determine the effect is faked (DC 8 plus your Charisma modifier and Proficiency Bonus).', 30),
    ('Athlete', 'Athlete: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Athlete', 'Athlete: Climb Speed', 'You gain a Climb Speed equal to your Speed.', 20),
    ('Athlete', 'Athlete: Hop Up', 'When you have the Prone condition, you can right yourself with only 5 feet of movement.', 30),
    ('Athlete', 'Athlete: Jumping', 'You can make a running Long or High Jump after moving only 5 feet.', 40),
    ('Blessed Warrior', 'Blessed Warrior Fighting Style', 'You learn two Cleric cantrips of your choice. Guidance and Sacred Flame are recommended. The chosen cantrips count as Paladin spells for you, and Charisma is your spellcasting ability for them. Whenever you gain a Paladin level, you can replace one of these cantrips with another Cleric cantrip.', 10),
    ('Blind Fighting', 'Blind Fighting Fighting Style', 'You have Blindsight with a range of 10 feet.', 10),
    ('Boon of Energy Resistance', 'Boon of Energy Resistance: Ability Score Increase', 'Increase one ability score of your choice by 1, to a maximum of 30.', 10),
    ('Boon of Energy Resistance', 'Boon of Energy Resistance: Energy Resistances', 'You gain Resistance to two of the following damage types of your choice: Acid, Cold, Fire, Lightning, Necrotic, Poison, Psychic, Radiant, or Thunder. Whenever you finish a Long Rest, you can change your choices.', 20),
    ('Boon of Energy Resistance', 'Boon of Energy Resistance: Energy Redirection', 'When you take damage of one of the types chosen for the Energy Resistances benefit, you can take a Reaction to direct damage of the same type toward another creature you can see within 60 feet of yourself that isn''t behind Total Cover. If you do so, that creature must succeed on a Dexterity saving throw (DC 8 plus your Constitution modifier and Proficiency Bonus) or take damage equal to 2d12 plus your Constitution modifier.', 30),
    ('Boon of Fortitude', 'Boon of Fortitude: Ability Score Increase', 'Increase one ability score of your choice by 1, to a maximum of 30.', 10),
    ('Boon of Fortitude', 'Boon of Fortitude: Fortified Health', 'Your Hit Point maximum increases by 40. In addition, whenever you regain Hit Points, you can regain additional Hit Points equal to your Constitution modifier. Once you''ve regained these additional Hit Points, you can''t do so again until the start of your next turn.', 20),
    ('Boon of Recovery', 'Boon of Recovery: Ability Score Increase', 'Increase one ability score of your choice by 1, to a maximum of 30.', 10),
    ('Boon of Recovery', 'Boon of Recovery: Last Stand', 'When you would be reduced to 0 Hit Points, you can drop to 1 Hit Point instead and regain a number of Hit Points equal to half your Hit Point maximum. Once you use this benefit, you can''t use it again until you finish a Long Rest.', 20),
    ('Boon of Recovery', 'Boon of Recovery: Recover Vitality', 'You have a pool of ten d10s. As a Bonus Action, you can expend dice from the pool, roll those dice, and regain a number of Hit Points equal to the roll''s total. You regain all the expended dice when you finish a Long Rest.', 30),
    ('Boon of Skill', 'Boon of Skill: Ability Score Increase', 'Increase one ability score of your choice by 1, to a maximum of 30.', 10),
    ('Boon of Skill', 'Boon of Skill: All-Around Adept', 'You gain proficiency in all skills.', 20),
    ('Boon of Skill', 'Boon of Skill: Expertise', 'Choose one skill in which you lack Expertise. You gain Expertise in that skill.', 30),
    ('Boon of Speed', 'Boon of Speed: Ability Score Increase', 'Increase one ability score of your choice by 1, to a maximum of 30.', 10),
    ('Boon of Speed', 'Boon of Speed: Escape Artist', 'As a Bonus Action, you can take the Disengage action, which also ends the Grappled condition on you.', 20),
    ('Boon of Speed', 'Boon of Speed: Quickness', 'Your Speed increases by 30 feet.', 30),
    ('Charger', 'Charger: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Charger', 'Charger: Improved Dash', 'When you take the Dash action, your Speed increases by 10 feet for that action.', 20),
    ('Charger', 'Charger: Charge Attack', 'If you move at least 10 feet in a straight line toward a target immediately before hitting it with a melee attack roll as part of the Attack action, choose one of the following effects: gain a 1d8 bonus to the attack''s damage roll, or push the target up to 10 feet away if it is no more than one size larger than you. You can use this benefit only once on each of your turns.', 30),
    ('Chef', 'Chef: Ability Score Increase', 'Increase your Constitution or Wisdom by 1, to a maximum of 20.', 10),
    ('Chef', 'Chef: Cook''s Utensils', 'You gain proficiency with Cook''s Utensils if you don''t already have it.', 20),
    ('Chef', 'Chef: Replenishing Meal', 'As part of a Short Rest, you can cook special food if you have ingredients and Cook''s Utensils on hand. You can prepare enough of this food for a number of creatures equal to 4 plus your Proficiency Bonus. At the end of the Short Rest, any creature who eats the food and spends one or more Hit Dice to regain Hit Points regains an extra 1d8 Hit Points.', 30),
    ('Chef', 'Chef: Bolstering Treats', 'With 1 hour of work or when you finish a Long Rest, you can cook a number of treats equal to your Proficiency Bonus if you have ingredients and Cook''s Utensils on hand. These special treats last 8 hours after being made. A creature can use a Bonus Action to eat one of those treats to gain a number of Temporary Hit Points equal to your Proficiency Bonus.', 40),
    ('Crafter', 'Crafter: Tool Proficiency', 'You gain proficiency with three different Artisan''s Tools of your choice from the Fast Crafting table.', 10),
    ('Crafter', 'Crafter: Discount', 'Whenever you buy a nonmagical item, you receive a 20 percent discount on it.', 20),
    ('Crafter', 'Crafter: Fast Crafting', 'When you finish a Long Rest, you can craft one piece of gear from the Fast Crafting table, provided you have the Artisan''s Tools associated with that item and have proficiency with those tools. The item lasts until you finish another Long Rest, at which point the item falls apart.', 30),
    ('Crossbow Expert', 'Crossbow Expert: Ability Score Increase', 'Increase your Dexterity score by 1, to a maximum of 20.', 10),
    ('Crossbow Expert', 'Crossbow Expert: Ignore Loading', 'You ignore the Loading property of the Hand Crossbow, Heavy Crossbow, and Light Crossbow (all called crossbows elsewhere in this feat). If you''re holding one of them, you can load a piece of ammunition into it even if you lack a free hand.', 20),
    ('Crossbow Expert', 'Crossbow Expert: Firing in Melee', 'Being within 5 feet of an enemy doesn''t impose Disadvantage on your attack rolls with crossbows.', 30),
    ('Crossbow Expert', 'Crossbow Expert: Dual Wielding', 'When you make the extra attack of the Light property, you can add your ability modifier to the damage of the extra attack if that attack is with a crossbow that has the Light property and you aren''t already adding that modifier to the damage.', 40),
    ('Crusher', 'Crusher: Ability Score Increase', 'Increase your Strength or Constitution by 1, to a maximum of 20.', 10),
    ('Crusher', 'Crusher: Push', 'Once per turn, when you hit a creature with an attack that deals Bludgeoning damage, you can move it 5 feet to an unoccupied space if the target is no more than one size larger than you.', 20),
    ('Crusher', 'Crusher: Enhanced Critical', 'When you score a Critical Hit that deals Bludgeoning damage to a creature, attack rolls against that creature have Advantage until the start of your next turn.', 30),
    ('Defensive Duelist', 'Defensive Duelist: Ability Score Increase', 'Increase your Dexterity score by 1, to a maximum of 20.', 10),
    ('Defensive Duelist', 'Defensive Duelist: Parry', 'If you''re holding a Finesse weapon and another creature hits you with a melee attack, you can take a Reaction to add your Proficiency Bonus to your Armor Class, potentially causing the attack to miss you. You gain this bonus to your AC against melee attacks until the start of your next turn.', 20),
    ('Druidic Warrior', 'Druidic Warrior Fighting Style', 'You learn two Druid cantrips of your choice. Guidance and Starry Wisp are recommended. The chosen cantrips count as Ranger spells for you, and Wisdom is your spellcasting ability for them. Whenever you gain a Ranger level, you can replace one of these cantrips with another Druid cantrip.', 10),
    ('Dual Wielder', 'Dual Wielder: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Dual Wielder', 'Dual Wielder: Enhanced Dual Wielding', 'When you take the Attack action on your turn and attack with a weapon that has the Light property, you can make one extra attack as a Bonus Action later on the same turn with a different weapon, which must be a Melee weapon that lacks the Two-Handed property. You don''t add your ability modifier to the extra attack''s damage unless that modifier is negative.', 20),
    ('Dual Wielder', 'Dual Wielder: Quick Draw', 'You can draw or stow two weapons that lack the Two-Handed property when you would normally be able to draw or stow only one.', 30),
    ('Dueling', 'Dueling Fighting Style', 'When you''re holding a Melee weapon in one hand and no other weapons, you gain a +2 bonus to damage rolls with that weapon.', 10),
    ('Durable', 'Durable: Ability Score Increase', 'Increase your Constitution score by 1, to a maximum of 20.', 10),
    ('Durable', 'Durable: Defy Death', 'You have Advantage on Death Saving Throws.', 20),
    ('Durable', 'Durable: Speedy Recovery', 'As a Bonus Action, you can expend one of your Hit Point Dice, roll the die, and regain a number of Hit Points equal to the roll.', 30),
    ('Elemental Adept', 'Elemental Adept: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('Elemental Adept', 'Elemental Adept: Energy Mastery', 'Choose one of the following damage types: Acid, Cold, Fire, Lightning, or Thunder. Spells you cast ignore Resistance to damage of the chosen type. In addition, when you roll damage for a spell you cast that deals damage of that type, you can treat any 1 on a damage die as a 2.', 20),
    ('Fey-Touched', 'Fey-Touched: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('Fey-Touched', 'Fey-Touched: Fey Magic', 'Choose one level 1 spell from the Divination or Enchantment school of magic. You always have that spell and the Misty Step spell prepared. You can cast each of these spells without expending a spell slot. Once you cast either spell in this way, you can''t cast that spell in this way again until you finish a Long Rest. You can also cast these spells using spell slots you have of the appropriate level. The spells'' spellcasting ability is the ability increased by this feat.', 20),
    ('Great Weapon Master', 'Great Weapon Master: Ability Score Increase', 'Increase your Strength score by 1, to a maximum of 20.', 10),
    ('Great Weapon Master', 'Great Weapon Master: Heavy Weapon Mastery', 'When you hit a creature with a weapon that has the Heavy property as part of the Attack action on your turn, you can cause the weapon to deal extra damage to the target. The extra damage equals your Proficiency Bonus.', 20),
    ('Great Weapon Master', 'Great Weapon Master: Hew', 'Immediately after you score a Critical Hit with a Melee weapon or reduce a creature to 0 Hit Points with one, you can make one attack with the same weapon as a Bonus Action.', 30),
    ('Healer', 'Healer: Battle Medic', 'If you have a Healer''s Kit, you can expend one use of it and tend to a creature within 5 feet of yourself as a Utilize action. That creature can expend one of its Hit Point Dice, and you then roll that die. The creature regains a number of Hit Points equal to the roll plus your Proficiency Bonus.', 10),
    ('Healer', 'Healer: Healing Rerolls', 'Whenever you roll a die to determine the number of Hit Points you restore with a spell or with this feat''s Battle Medic benefit, you can reroll the die if it rolls a 1, and you must use the new roll.', 20),
    ('Heavily Armored', 'Heavily Armored: Ability Score Increase', 'Increase your Constitution or Strength by 1, to a maximum of 20.', 10),
    ('Heavily Armored', 'Heavily Armored: Armor Training', 'You gain training with Heavy armor.', 20),
    ('Heavy Armor Master', 'Heavy Armor Master: Ability Score Increase', 'Increase your Constitution or Strength by 1, to a maximum of 20.', 10),
    ('Heavy Armor Master', 'Heavy Armor Master: Damage Reduction', 'When you''re hit by an attack while you''re wearing Heavy armor, any Bludgeoning, Piercing, and Slashing damage dealt to you by that attack is reduced by an amount equal to your Proficiency Bonus.', 20),
    ('Inspiring Leader', 'Inspiring Leader: Ability Score Increase', 'Increase your Wisdom or Charisma by 1, to a maximum of 20.', 10),
    ('Inspiring Leader', 'Inspiring Leader: Bolstering Performance', 'When you finish a Short or Long Rest, you can give an inspiring performance: a speech, song, or dance. When you do so, choose up to six allies (which can include yourself) within 30 feet of yourself who witness the performance. The chosen creatures each gain Temporary Hit Points equal to your character level plus the modifier of the ability you increased with this feat.', 20),
    ('Interception', 'Interception Fighting Style', 'When a creature you can see hits another creature within 5 feet of you with an attack roll, you can take a Reaction to reduce the damage dealt to the target by 1d10 plus your Proficiency Bonus. You must be holding a Shield or a Simple or Martial weapon to use this Reaction.', 10),
    ('Keen Mind', 'Keen Mind: Ability Score Increase', 'Increase your Intelligence score by 1, to a maximum of 20.', 10),
    ('Keen Mind', 'Keen Mind: Lore Knowledge', 'Choose one of the following skills: Arcana, History, Investigation, Nature, or Religion. If you lack proficiency in the chosen skill, you gain proficiency in it, and if you already have proficiency in it, you gain Expertise in it.', 20),
    ('Keen Mind', 'Keen Mind: Quick Study', 'You can take the Study action as a Bonus Action.', 30),
    ('Lightly Armored', 'Lightly Armored: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Lightly Armored', 'Lightly Armored: Armor Training', 'You gain training with Light armor and Shields.', 20),
    ('Lucky', 'Lucky: Luck Points', 'You have a number of Luck Points equal to your Proficiency Bonus and can spend the points on the benefits below. You regain your expended Luck Points when you finish a Long Rest.', 10),
    ('Lucky', 'Lucky: Advantage', 'When you roll a d20 for a D20 Test, you can spend 1 Luck Point to give yourself Advantage on the roll.', 20),
    ('Lucky', 'Lucky: Disadvantage', 'When a creature rolls a d20 for an attack roll against you, you can spend 1 Luck Point to impose Disadvantage on that roll.', 30),
    ('Mage Slayer', 'Mage Slayer: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Mage Slayer', 'Mage Slayer: Concentration Breaker', 'When you damage a creature that is Concentrating, it has Disadvantage on the saving throw it makes to maintain Concentration.', 20),
    ('Mage Slayer', 'Mage Slayer: Guarded Mind', 'If you fail an Intelligence, a Wisdom, or a Charisma saving throw, you can cause yourself to succeed instead. Once you use this benefit, you can''t use it again until you finish a Short or Long Rest.', 30),
    ('Martial Weapon Training', 'Martial Weapon Training: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Martial Weapon Training', 'Martial Weapon Training: Weapon Proficiency', 'You gain proficiency with Martial weapons.', 20),
    ('Medium Armor Master', 'Medium Armor Master: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Medium Armor Master', 'Medium Armor Master: Dexterous Wearer', 'While you''re wearing Medium armor, you can add 3, rather than 2 to your AC if you have a Dexterity score of 16 or higher.', 20),
    ('Moderately Armored', 'Moderately Armored: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Moderately Armored', 'Moderately Armored: Armor Training', 'You gain training with Medium armor.', 20),
    ('Mounted Combatant', 'Mounted Combatant: Ability Score Increase', 'Increase your Strength, Dexterity, or Wisdom by 1, to a maximum of 20.', 10),
    ('Mounted Combatant', 'Mounted Combatant: Mounted Strike', 'While mounted, you have Advantage on attack rolls against any unmounted creature within 5 feet of your mount that is at least one size smaller than the mount.', 20),
    ('Mounted Combatant', 'Mounted Combatant: Leap Aside', 'If your mount is subjected to an effect that allows it to make a Dexterity saving throw to take only half damage, it instead takes no damage if it succeeds on the saving throw and only half damage if it fails. For your mount to gain this benefit, you must be riding it, and neither of you can have the Incapacitated condition.', 30),
    ('Mounted Combatant', 'Mounted Combatant: Veer', 'While mounted, you can force an attack that hits your mount to hit you instead if you don''t have the Incapacitated condition.', 40),
    ('Musician', 'Musician: Instrument Training', 'You gain proficiency with three Musical Instruments of your choice.', 10),
    ('Musician', 'Musician: Encouraging Song', 'As you finish a Short or Long Rest, you can play a song on a Musical Instrument with which you have proficiency and give Heroic Inspiration to allies who hear the song. The number of allies you can affect in this way equals your Proficiency Bonus.', 20),
    ('Observant', 'Observant: Ability Score Increase', 'Increase your Intelligence or Wisdom by 1, to a maximum of 20.', 10),
    ('Observant', 'Observant: Keen Observer', 'Choose one of the following skills: Insight, Investigation, or Perception. If you lack proficiency with the chosen skill, you gain proficiency in it, and if you already have proficiency in it, you gain Expertise in it.', 20),
    ('Observant', 'Observant: Quick Search', 'You can take the Search action as a Bonus Action.', 30),
    ('Piercer', 'Piercer: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Piercer', 'Piercer: Puncture', 'Once per turn, when you hit a creature with an attack that deals Piercing damage, you can reroll one of the attack''s damage dice, and you must use the new roll.', 20),
    ('Piercer', 'Piercer: Enhanced Critical', 'When you score a Critical Hit that deals Piercing damage to a creature, you can roll one additional damage die when determining the extra Piercing damage the target takes.', 30),
    ('Poisoner', 'Poisoner: Ability Score Increase', 'Increase your Dexterity or Intelligence by 1, to a maximum of 20.', 10),
    ('Poisoner', 'Poisoner: Potent Poison', 'When you make a damage roll that deals Poison damage, it ignores Resistance to Poison damage.', 20),
    ('Poisoner', 'Poisoner: Brew Poison', 'You gain proficiency with the Poisoner''s Kit. With 1 hour of work using such a kit and expending 50 GP worth of materials, you can create a number of poison doses equal to your Proficiency Bonus. As a Bonus Action, you can apply a poison dose to a weapon or piece of ammunition. Once applied, the poison retains its potency for 1 minute or until you deal damage with the poisoned item, whichever is shorter. When a creature takes damage from the poisoned item, that creature must succeed on a Constitution saving throw (DC 8 plus the modifier of the ability increased by this feat and your Proficiency Bonus) or take 2d8 Poison damage and have the Poisoned condition until the end of your next turn.', 30),
    ('Polearm Master', 'Polearm Master: Ability Score Increase', 'Increase your Dexterity or Strength by 1, to a maximum of 20.', 10),
    ('Polearm Master', 'Polearm Master: Pole Strike', 'Immediately after you take the Attack action and attack with a Quarterstaff, a Spear, or a weapon that has the Heavy and Reach properties, you can use a Bonus Action to make a melee attack with the opposite end of the weapon. The weapon deals Bludgeoning damage, and the weapon''s damage die for this attack is a d4.', 20),
    ('Polearm Master', 'Polearm Master: Reactive Strike', 'While you''re holding a Quarterstaff, a Spear, or a weapon that has the Heavy and Reach properties, you can take a Reaction to make one melee attack against a creature that enters the reach you have with that weapon.', 30),
    ('Protection', 'Protection Fighting Style', 'When a creature you can see attacks a target other than you that is within 5 feet of you, you can take a Reaction to interpose your Shield if you''re holding one. You impose Disadvantage on the triggering attack roll and all other attack rolls against the target until the start of your next turn if you remain within 5 feet of the target.', 10),
    ('Resilient', 'Resilient: Ability Score Increase', 'Choose one ability in which you lack saving throw proficiency. Increase the chosen ability score by 1, to a maximum of 20.', 10),
    ('Resilient', 'Resilient: Saving Throw Proficiency', 'You gain saving throw proficiency with the chosen ability.', 20),
    ('Ritual Caster', 'Ritual Caster: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('Ritual Caster', 'Ritual Caster: Ritual Spells', 'Choose a number of level 1 spells equal to your Proficiency Bonus that have the Ritual tag. You always have those spells prepared, and you can cast them with any spell slots you have. The spells'' spellcasting ability is the ability increased by this feat. Whenever your Proficiency Bonus increases thereafter, you can add an additional level 1 spell with the Ritual tag to the spells always prepared with this feature.', 20),
    ('Ritual Caster', 'Ritual Caster: Quick Ritual', 'With this benefit, you can cast a Ritual spell that you have prepared using its regular casting time rather than the extended time for a Ritual. Doing so doesn''t require a spell slot. Once you cast the spell in this way, you can''t use this benefit again until you finish a Long Rest.', 30),
    ('Sentinel', 'Sentinel: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Sentinel', 'Sentinel: Guardian', 'Immediately after a creature within 5 feet of you takes the Disengage action or hits a target other than you with an attack, you can make an Opportunity Attack against that creature.', 20),
    ('Sentinel', 'Sentinel: Halt', 'When you hit a creature with an Opportunity Attack, the creature''s Speed becomes 0 for the rest of the current turn.', 30),
    ('Shadow-Touched', 'Shadow-Touched: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('Shadow-Touched', 'Shadow-Touched: Shadow Magic', 'Choose one level 1 spell from the Illusion or Necromancy school of magic. You always have that spell and the Invisibility spell prepared. You can cast each of these spells without expending a spell slot. Once you cast either spell in this way, you can''t cast that spell in this way again until you finish a Long Rest. You can also cast these spells using spell slots you have of the appropriate level. The spells'' spellcasting ability is the ability increased by this feat.', 20),
    ('Sharpshooter', 'Sharpshooter: Ability Score Increase', 'Increase your Dexterity score by 1, to a maximum of 20.', 10),
    ('Sharpshooter', 'Sharpshooter: Bypass Cover', 'Your ranged attacks with weapons ignore Half Cover and Three-Quarters Cover.', 20),
    ('Sharpshooter', 'Sharpshooter: Firing in Melee', 'Being within 5 feet of an enemy doesn''t impose Disadvantage on your attack rolls with Ranged weapons.', 30),
    ('Sharpshooter', 'Sharpshooter: Long Shots', 'Attacking at long range doesn''t impose Disadvantage on your attack rolls with Ranged weapons.', 40),
    ('Shield Master', 'Shield Master: Ability Score Increase', 'Increase your Strength score by 1, to a maximum of 20.', 10),
    ('Shield Master', 'Shield Master: Shield Bash', 'If you attack a creature within 5 feet of you as part of the Attack action and hit with a Melee weapon, you can immediately bash the target with your Shield if it''s equipped, forcing the target to make a Strength saving throw (DC 8 plus your Strength modifier and Proficiency Bonus). On a failed save, you either push the target 5 feet from you or cause it to have the Prone condition (your choice). You can use this benefit only once on each of your turns.', 20),
    ('Shield Master', 'Shield Master: Interpose Shield', 'If you''re subjected to an effect that allows you to make a Dexterity saving throw to take only half damage, you can take a Reaction to take no damage if you succeed on the saving throw and are holding a Shield.', 30),
    ('Skill Expert', 'Skill Expert: Ability Score Increase', 'Increase one ability score of your choice by 1, to a maximum of 20.', 10),
    ('Skill Expert', 'Skill Expert: Skill Proficiency', 'You gain proficiency in one skill of your choice.', 20),
    ('Skill Expert', 'Skill Expert: Expertise', 'Choose one skill in which you have proficiency but lack Expertise. You gain Expertise with that skill.', 30),
    ('Skulker', 'Skulker: Ability Score Increase', 'Increase your Dexterity score by 1, to a maximum of 20.', 10),
    ('Skulker', 'Skulker: Blindsight', 'You have Blindsight with a range of 10 feet.', 20),
    ('Skulker', 'Skulker: Fog of War', 'You exploit the distractions of battle, gaining Advantage on any Dexterity (Stealth) check you make as part of the Hide action during combat.', 30),
    ('Skulker', 'Skulker: Sniper', 'If you make an attack roll while hidden and the roll misses, making the attack roll doesn''t reveal your location.', 40),
    ('Slasher', 'Slasher: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Slasher', 'Slasher: Hamstring', 'Once per turn when you hit a creature with an attack that deals Slashing damage, you can reduce the Speed of that creature by 10 feet until the start of your next turn.', 20),
    ('Slasher', 'Slasher: Enhanced Critical', 'When you score a Critical Hit that deals Slashing damage to a creature, it has Disadvantage on attack rolls until the start of your next turn.', 30),
    ('Speedy', 'Speedy: Ability Score Increase', 'Increase your Dexterity or Constitution by 1, to a maximum of 20.', 10),
    ('Speedy', 'Speedy: Speed Increase', 'Your Speed increases by 10 feet.', 20),
    ('Speedy', 'Speedy: Dash over Difficult Terrain', 'When you take the Dash action on your turn, Difficult Terrain doesn''t cost you extra movement for the rest of that turn.', 30),
    ('Speedy', 'Speedy: Agile Movement', 'Opportunity Attacks have Disadvantage against you.', 40),
    ('Spell Sniper', 'Spell Sniper: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('Spell Sniper', 'Spell Sniper: Bypass Cover', 'Your attack rolls for spells ignore Half Cover and Three-Quarters Cover.', 20),
    ('Spell Sniper', 'Spell Sniper: Casting in Melee', 'Being within 5 feet of an enemy doesn''t impose Disadvantage on your attack rolls with spells.', 30),
    ('Spell Sniper', 'Spell Sniper: Increased Range', 'When you cast a spell that has a range of at least 10 feet and requires you to make an attack roll, you can increase the spell''s range by 60 feet.', 40),
    ('Tavern Brawler', 'Tavern Brawler: Enhanced Unarmed Strike', 'When you hit with your Unarmed Strike and deal damage, you can deal Bludgeoning damage equal to 1d4 plus your Strength modifier instead of the normal damage of an Unarmed Strike.', 10),
    ('Tavern Brawler', 'Tavern Brawler: Damage Rerolls', 'Whenever you roll a damage die for your Unarmed Strike, you can reroll the die if it rolls a 1, and you must use the new roll.', 20),
    ('Tavern Brawler', 'Tavern Brawler: Improvised Weaponry', 'You have proficiency with improvised weapons.', 30),
    ('Tavern Brawler', 'Tavern Brawler: Push', 'When you hit a creature with an Unarmed Strike as part of the Attack action on your turn, you can deal damage to the target and also push it 5 feet away from you. You can use this benefit only once per turn.', 40),
    ('Telekinetic', 'Telekinetic: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('Telekinetic', 'Telekinetic: Minor Telekinesis', 'You learn the Mage Hand spell. You can cast it without Verbal or Somatic components, you can make the spectral hand Invisible, and its range and the distance it can be away from you both increase by 30 feet when you cast it. The spell''s spellcasting ability is the ability increased by this feat.', 20),
    ('Telekinetic', 'Telekinetic: Telekinetic Shove', 'As a Bonus Action, you can telekinetically shove one creature you can see within 30 feet of yourself. When you do so, the target must succeed on a Strength saving throw (DC 8 plus the ability modifier of the score increased by this feat and your Proficiency Bonus) or be moved 5 feet toward or away from you.', 30),
    ('Telepathic', 'Telepathic: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('Telepathic', 'Telepathic: Telepathic Utterance', 'You can speak telepathically to any creature you can see within 60 feet of yourself. Your telepathic utterances are in a language you know, and the creature understands you only if it knows that language. Your communication doesn''t give the creature the ability to respond to you telepathically.', 20),
    ('Telepathic', 'Telepathic: Detect Thoughts', 'You always have the Detect Thoughts spell prepared. You can cast it without a spell slot or spell components, and you must finish a Long Rest before you can cast it in this way again. You can also cast it using spell slots you have of the appropriate level. Your spellcasting ability for the spell is the ability increased by this feat.', 30),
    ('Thrown Weapon Fighting', 'Thrown Weapon Fighting Fighting Style', 'When you hit with a ranged attack roll using a weapon that has the Thrown property, you gain a +2 bonus to the damage roll.', 10),
    ('Tough', 'Tough', 'Your Hit Point maximum increases by an amount equal to twice your character level when you gain this feat. Whenever you gain a character level thereafter, your Hit Point maximum increases by an additional 2 Hit Points.', 10),
    ('Unarmed Fighting', 'Unarmed Fighting Fighting Style', 'When you hit with your Unarmed Strike and deal damage, you can deal Bludgeoning damage equal to 1d6 plus your Strength modifier instead of the normal damage of an Unarmed Strike. If you aren''t holding any weapons or a Shield when you make the attack roll, the d6 becomes a d8.', 10),
    ('War Caster', 'War Caster: Ability Score Increase', 'Increase your Intelligence, Wisdom, or Charisma by 1, to a maximum of 20.', 10),
    ('War Caster', 'War Caster: Concentration', 'You have Advantage on Constitution saving throws that you make to maintain Concentration.', 20),
    ('War Caster', 'War Caster: Reactive Spell', 'When a creature provokes an Opportunity Attack from you by leaving your reach, you can take a Reaction to cast a spell at the creature rather than making an Opportunity Attack. The spell must have a casting time of one action and must target only that creature.', 30),
    ('War Caster', 'War Caster: Somatic Components', 'You can perform the Somatic components of spells even when you have weapons or a Shield in one or both hands.', 40),
    ('Weapon Master', 'Weapon Master: Ability Score Increase', 'Increase your Strength or Dexterity by 1, to a maximum of 20.', 10),
    ('Weapon Master', 'Weapon Master: Mastery Property', 'Your training with weapons allows you to use the mastery property of one kind of Simple or Martial weapon of your choice, provided you have proficiency with it. Whenever you finish a Long Rest, you can change the kind of weapon to another eligible kind.', 20);
