INSERT INTO _import_feat_trait_option_data (trait_name, option_group, option_name, description, sort_order) VALUES
    ('Actor: Ability Score Increase', 'Ability Score', 'Charisma', 'Increase Charisma by 1.', 10),
    ('Athlete: Ability Score Increase', 'Ability Score', 'Strength', 'Increase Strength by 1.', 10),
    ('Athlete: Ability Score Increase', 'Ability Score', 'Dexterity', 'Increase Dexterity by 1.', 20),
    ('Boon of Energy Resistance: Ability Score Increase', 'Ability Score', 'Strength', 'Increase Strength by 1.', 10),
    ('Boon of Energy Resistance: Ability Score Increase', 'Ability Score', 'Dexterity', 'Increase Dexterity by 1.', 20),
    ('Boon of Energy Resistance: Ability Score Increase', 'Ability Score', 'Constitution', 'Increase Constitution by 1.', 30),
    ('Boon of Energy Resistance: Ability Score Increase', 'Ability Score', 'Intelligence', 'Increase Intelligence by 1.', 40),
