WITH crafter_trait AS (
    SELECT id
    FROM traits
    WHERE name = 'Crafter: Tool Proficiency'
),
artisan_tools AS (
    SELECT
        id AS tool_id,
        name,
        'Gain proficiency with ' || name || '.' AS description,
        (100 + row_number() OVER (ORDER BY name))::INT AS sort_order
    FROM tools
    WHERE category = 'Artisan'
)
    trait_id,
    option_group,
    tool_id,
    name,
    description,
    sort_order
)
SELECT
    crafter_trait.id,
    'Artisan Tools',
    artisan_tools.tool_id,
    artisan_tools.name,
    artisan_tools.description,
    artisan_tools.sort_order
FROM crafter_trait
CROSS JOIN artisan_tools
ON CONFLICT (trait_id, option_group, name) DO UPDATE SET
    tool_id = EXCLUDED.tool_id,
    description = EXCLUDED.description,
    sort_order = EXCLUDED.sort_order;

WITH musician_trait AS (
    SELECT id
    FROM traits
    WHERE name = 'Musician: Instrument Training'
),
instrument_tools AS (
    SELECT
        id AS tool_id,
        name,
        'Gain proficiency with ' || name || '.' AS description,
        (100 + row_number() OVER (ORDER BY name))::INT AS sort_order
    FROM tools
    WHERE category = 'Musical Instrument'
)
    trait_id,
    option_group,
    tool_id,
    name,
    description,
    sort_order
)
SELECT
    musician_trait.id,
    'Musical Instrument',
    instrument_tools.tool_id,
    instrument_tools.name,
    instrument_tools.description,
    instrument_tools.sort_order
FROM musician_trait
CROSS JOIN instrument_tools
ON CONFLICT (trait_id, option_group, name) DO UPDATE SET
    tool_id = EXCLUDED.tool_id,
    description = EXCLUDED.description,
    sort_order = EXCLUDED.sort_order;

